// Description: Collects per-route HAProxy ingress metrics via Thanos Querier.
// Description: Reports request rate, 5xx errors, response time, connection errors, backend status.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

def routeName = instanceProps.get("auto.route.name")
def routeNs = instanceProps.get("auto.route.namespace")

def results = [
    "request_rate": 0,
    "error_rate_5xx": 0,
    "response_time_avg_ms": 0,
    "connection_errors": 0,
    "backend_up": 0,
    "active_sessions": 0
]

if (!host || !token || !routeName || !routeNs) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

// Try both possible response time metric names
def responseTimeMetric = 'avg(haproxy_server_http_average_response_latency_milliseconds{route="' + routeName + '",exported_namespace="' + routeNs + '"}) or vector(0)'
def responseTimeFallback = 'avg(haproxy_server_response_time_average_seconds{route="' + routeName + '",exported_namespace="' + routeNs + '"}) or vector(0)'

def metrics = [
    "request_rate": 'sum(rate(haproxy_server_http_responses_total{route="' + routeName + '",exported_namespace="' + routeNs + '"}[5m])) or vector(0)',
    "error_rate_5xx": 'sum(rate(haproxy_server_http_responses_total{route="' + routeName + '",exported_namespace="' + routeNs + '",code="5xx"}[5m])) or vector(0)',
    "response_time_avg_ms": responseTimeMetric,
    "connection_errors": 'sum(rate(haproxy_backend_connection_errors_total{route="' + routeName + '",exported_namespace="' + routeNs + '"}[5m])) or vector(0)',
    "backend_up": 'min(haproxy_server_up{route="' + routeName + '",exported_namespace="' + routeNs + '"}) or vector(0)',
    "active_sessions": 'sum(haproxy_server_current_sessions{route="' + routeName + '",exported_namespace="' + routeNs + '"}) or vector(0)'
]

metrics.each { dp, query ->
    def val = executeQuery(query, baseUrl, token)
    if (val != null) {
        results[dp] = val as Double
    }
}

// If primary response time metric returned 0, try fallback (seconds -> ms)
if (results["response_time_avg_ms"] == 0) {
    def val = executeQuery(responseTimeFallback, baseUrl, token)
    if (val != null) {
        results["response_time_avg_ms"] = (val as Double) * 1000
    }
}

results.each { k, v -> println("${k}:${v}") }
return 0
